text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표 시점은 금요일 15:00 KST로 한다.",
        "condition": "스모크 테스트 통과",
        "certainty": "confirmed"
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "condition": "packageName mismatch 발생 시",
        "certainty": "confirmed"
      },
      {
        "decision": "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다.",
        "condition": "패키지 계약이 잘못된 것으로 확인된 경우",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "outcome": "rejected",
        "reason": "논의 후, 불일치 발생 시 먼저 패키지 설정과 계약을 확인하기로 결정됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "internal_stretch_goal_only",
        "note": "Doyun이 스모크 테스트 통과가 먼저 필요하다고 반대했으며, 최종 공개 릴리스 목표는 금요일 15:00 KST로 확정됨"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 목요일까지 가능하면 검토해야 한다는 의견이 있었으나, 담당자는 지정되지 않았다.",
        "status": "not_confirmed"
      },
      {
        "item": "Hara가 Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인하기로 했으나, 정확한 마감 시각은 정해지지 않았다.",
        "status": "partially_confirmed"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다.",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 단계가 오래된 경우 릴리스 노트가 사용자를 오도할 수 있다.",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "open"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?",
        "status": "open"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "unassigned_non_decision",
      "source_certainty": "mentioned_without_owner"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 공유한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed_without_exact_deadline",
      "source_certainty": "explicit_task_no_exact_deadline"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과 공유 여부를 확인한다.",
      "Doyun의 금요일 12:00 KST action_items.md 실패 triage note 작성 여부를 확인한다.",
      "스모크 테스트 통과 여부에 따라 금요일 15:00 KST 공개 릴리스 목표를 유지할 수 있는지 확인한다.",
      "Minjun의 스모크 결과 이후 Hara가 생성된 tarball 경로를 확인했는지 확인한다.",
      "README 설치 단계 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 담당자",
      "명시되지 않은 마감 시각",
      "스모크 테스트 결과",
      "최종 승인권자"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owner": "명시되지 않은 담당자는 임의 배정하지 않는다.",
    "deadline": "정확한 마감이 없는 항목에는 임의 마감 시각을 부여하지 않는다.",
    "release_authority": "최종 릴리스 승인 권한자는 열린 질문으로 유지한다."
  }
}
